<section class="auth-wrap"><div class="auth-art"><span>MAISON AI</span><div><blockquote>“Style is a way to say who you are without having to speak.”</blockquote><small>YOUR PRIVATE DIGITAL ATELIER</small></div></div><div class="auth-form"><div class="auth-inner"><span class="eyebrow"><?= $mode==='login'?'WELCOME BACK':'JOIN THE MAISON' ?></span><h1><?= $mode==='login'?'Return to your atelier':'Create your account' ?></h1><p><?= $mode==='login'?'Your saved looks and personal edit are waiting.':'Save looks, curate favorites, and make every fitting personal.' ?></p><?php if (!empty($error)): ?><div class="alert alert-danger"><?= html_escape($error) ?></div><?php endif ?><?= validation_errors('<div class="alert alert-danger">','</div>') ?><form method="post"><div class="vstack gap-3"><?php if($mode==='register'): ?><div><label>Name</label><input class="form-control form-control-lg" name="name" value="<?= set_value('name') ?>" required autocomplete="name"></div><?php endif ?><div><label>Email</label><input class="form-control form-control-lg" name="email" type="email" value="<?= set_value('email') ?>" required autocomplete="email"></div><div><label>Password</label><input class="form-control form-control-lg" name="password" type="password" required autocomplete="<?= $mode==='login'?'current-password':'new-password' ?>"></div><button class="btn btn-ink btn-lg mt-2"><?= $mode==='login'?'Sign in':'Create account' ?></button></div></form><p class="auth-switch"><?= $mode==='login'?'New to Maison? <a href="'.site_url('register').'">Create an account</a>':'Already a member? <a href="'.site_url('login').'">Sign in</a>' ?></p></div></div></section>
